def first(n): # returns first n terms
    f0, f1 = "01"
    while len(f0) < n:
        f0, f1 = 2*f0+f1, f0
    return list(map(int, f0[0:n])) # _A.H.M. Smeets_, Apr 11 2026, edited by _Michael S. Branicky_, Apr 18 2026

